-- Grant CONNECT privilege (CREATE SESSION) to all users
GRANT CONNECT TO app_user01;
GRANT CONNECT TO app_user02;
GRANT CONNECT TO app_user03;

-- Grant CREATE TABLE privilege for development
GRANT CREATE TABLE TO app_user01;
GRANT CREATE TABLE TO app_user02;
GRANT CREATE TABLE TO app_user03;

-- Grant additional resource privileges
GRANT CREATE SEQUENCE TO app_user01;
GRANT CREATE SEQUENCE TO app_user02;
GRANT CREATE SEQUENCE TO app_user03;

GRANT CREATE PROCEDURE TO app_user01;
GRANT CREATE PROCEDURE TO app_user02;
GRANT CREATE PROCEDURE TO app_user03;

-- Create a custom role for DML operations
CREATE ROLE app_dml_role;

-- Grant privileges to the role
GRANT CREATE SESSION TO app_dml_role;
GRANT CREATE TABLE TO app_dml_role;
GRANT CREATE SEQUENCE TO app_dml_role;
GRANT CREATE PROCEDURE TO app_dml_role;
GRANT CREATE VIEW TO app_dml_role;
GRANT CREATE INDEX TO app_dml_role;
GRANT CREATE TRIGGER TO app_dml_role;
GRANT UNLIMITED TABLESPACE TO app_dml_role;

-- Grant the custom role to app_user03
GRANT app_dml_role TO app_user03;

-- Verify the role assignment
SELECT * FROM dba_role_privs
WHERE grantee = 'APP_USER03';

-- Set warning threshold at 85% for User 1 tablespace
ALTER TABLESPACE app_user01_ts
  STORAGE (MAXEXTENTS UNLIMITED);

-- Create alert for app_user01_ts at 85%
BEGIN
  DBMS_SPACE_ADMIN.TABLESPACE_THRESHOLD_ALERT(
    ts_name => 'APP_USER01_TS',
    threshold_type => DBMS_SPACE_ADMIN.THRESHOLD_PERCENT,
    threshold_value => 85,
    alert_type => DBMS_SPACE_ADMIN.ALERT_ON_PERCENT
  );
END;
/

